package com.hr.management;

import javax.jws.WebMethod;
import javax.jws.WebService;
import javax.jws.soap.SOAPBinding;
import java.util.HashMap;
import java.util.Map;

@WebService
@SOAPBinding(style = SOAPBinding.Style.DOCUMENT, use = SOAPBinding.Use.LITERAL)
public class HRManagementService {

    private Map<String, Employee> employees = new HashMap<>();

    public HRManagementService() {
        // Initialize with some sample data for demonstration
        employees.put("E001", new Employee("John Doe", 50000.0, "Excellent"));
        employees.put("E002", new Employee("Jane Smith", 48000.0, "Good"));
    }

    @WebMethod(operationName = "updateSalary")
    public boolean updateSalary(String employeeId, double salary) {
        if (employees.containsKey(employeeId)) {
            employees.get(employeeId).setSalary(salary);
            return true;
        }
        return false;
    }

    @WebMethod(operationName = "performReview")
    public boolean performReview(String employeeId, String review) {
        if (employees.containsKey(employeeId)) {
            employees.get(employeeId).setPerformanceReview(review);
            return true;
        }
        return false;
    }

    @WebMethod(operationName = "terminateEmployee")
    public boolean terminateEmployee(String employeeId) {
        return employees.remove(employeeId) != null;
    }

    private static class Employee {
        private String name;
        private double salary;
        private String performanceReview;

        public Employee(String name, double salary, String performanceReview) {
            this.name = name;
            this.salary = salary;
            this.performanceReview = performanceReview;
        }

        public void setSalary(double salary) {
            this.salary = salary;
        }

        public void setPerformanceReview(String performanceReview) {
            this.performanceReview = performanceReview;
        }
    }
}